"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[442],{21428(n,r,e){e.r(r),e.d(r,{assets:()=>i,contentTitle:()=>o,default:()=>l,frontMatter:()=>a,metadata:()=>t,toc:()=>p});const t=JSON.parse('{"id":"cpp20/concepts-basics","title":"Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)","description":"C++20 Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/01-concepts-basics.md","sourceDirName":"cpp20","slug":"/cpp20/01-concepts-basics","permalink":"/LearnModernCpp/docs/cpp20/01-concepts-basics","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"concepts_basics","permalink":"/LearnModernCpp/docs/tags/concepts-basics"}],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2,"slug":"01-concepts-basics","title":"Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)","description":"C++20 Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","concepts_basics"]},"sidebar":"docs","previous":{"title":"C++20 \u65b0\u7279\u6027\u6982\u89c8","permalink":"/LearnModernCpp/docs/cpp20/"},"next":{"title":"Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)","permalink":"/LearnModernCpp/docs/cpp20/02-concepts-advanced"}}');var s=e(74848),c=e(28453);const a={sidebar_position:2,slug:"01-concepts-basics",title:"Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)",description:"C++20 Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","concepts_basics"]},o="Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)",i={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function d(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,c.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(r.header,{children:(0,s.jsx)(r.h1,{id:"concepts-\u57fa\u7840-conceptrequires\u5b50\u53e5",children:"Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)"})}),"\n",(0,s.jsx)(r.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(r.pre,{children:(0,s.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp20/01_concepts_basics.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: Concepts \u662f\u4e00\u79cd\u5bf9\u6a21\u677f\u53c2\u6570\u8fdb\u884c\u7ea6\u675f\u7684\u673a\u5236\uff0c\r\n *          \u4f7f\u7528 requires \u5b50\u53e5\u53ef\u4ee5\u660e\u786e\u6307\u5b9a\u6a21\u677f\u53c2\u6570\u9700\u8981\u6ee1\u8db3\u7684\u6761\u4ef6\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u5728 C++20 \u4e4b\u524d\uff0c\u6a21\u677f\u53c2\u6570\u7ea6\u675f\u4f9d\u8d56 SFINAE\uff0c\r\n *             \u5bfc\u81f4\u9519\u8bef\u4fe1\u606f\u6666\u6da9\u96be\u61c2\u3001\u4ee3\u7801\u53ef\u8bfb\u6027\u5dee\u3002\r\n *             Concepts \u63d0\u4f9b\u4e86\u7b80\u6d01\u3001\u76f4\u89c2\u7684\u7ea6\u675f\u8bed\u6cd5\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u6807\u51c6\u5e93\u63d0\u4f9b\u4e86 std::integral\u3001std::floating_point \u7b49\u5185\u7f6e concept\r\n *   - requires \u5b50\u53e5\u53ef\u4ee5\u76f4\u63a5\u7ea6\u675f\u6a21\u677f\u53c2\u6570\r\n *   - \u4e0e SFINAE \u76f8\u6bd4\uff0c\u9519\u8bef\u4fe1\u606f\u66f4\u6e05\u6670\u3001\u8bed\u6cd5\u66f4\u7b80\u6d01\r\n *   - concept \u7ea6\u675f\u53ef\u4ee5\u51fa\u73b0\u5728\u591a\u4e2a\u4f4d\u7f6e\uff08\u6a21\u677f\u53c2\u6570\u3001\u8fd4\u56de\u7c7b\u578b\u524d\u3001\u5c3e\u90e8\uff09\r\n * ============================================================\r\n */\r\n\r\n#include <concepts>\r\n#include <iostream>\r\n#include <string>\r\n#include <type_traits>\r\n\r\n// ===================== basic_usage() =====================\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. \u4f7f\u7528\u5185\u7f6e concept: std::integral\r\n    // \u7ea6\u675f\u6a21\u677f\u53c2\u6570 T \u5fc5\u987b\u662f\u6574\u6570\u7c7b\u578b\r\n    auto add_integers = []<std::integral T>(T a, T b) -> T {\r\n        return a + b;\r\n    };\r\n\r\n    std::cout << "\u6574\u6570\u52a0\u6cd5: 3 + 5 = " << add_integers(3, 5) << "\\n";\r\n    std::cout << "\u957f\u6574\u6570\u52a0\u6cd5: 100L + 200L = " << add_integers(100L, 200L) << "\\n";\r\n    // add_integers(3.14, 2.71);  // \u7f16\u8bd1\u9519\u8bef\uff01double \u4e0d\u6ee1\u8db3 std::integral\r\n\r\n    // 2. \u4f7f\u7528\u5185\u7f6e concept: std::floating_point\r\n    auto multiply_floats = []<std::floating_point T>(T a, T b) -> T {\r\n        return a * b;\r\n    };\r\n\r\n    std::cout << "\u6d6e\u70b9\u4e58\u6cd5: 3.14 * 2.0 = " << multiply_floats(3.14, 2.0) << "\\n";\r\n    // multiply_floats(3, 5);  // \u7f16\u8bd1\u9519\u8bef\uff01int \u4e0d\u6ee1\u8db3 std::floating_point\r\n\r\n    // 3. requires \u5b50\u53e5\u7ea6\u675f\u6a21\u677f\u51fd\u6570\r\n    // \u65b9\u5f0f\u4e00\uff1a\u5c3e\u90e8 requires \u5b50\u53e5\r\n    auto safe_divide = []<typename T>(T a, T b) -> T\r\n        requires std::floating_point<T>\r\n    {\r\n        if (b == T{0}) {\r\n            std::cout << "  [\u8b66\u544a] \u9664\u6570\u4e3a\u96f6!\\n";\r\n            return T{0};\r\n        }\r\n        return a / b;\r\n    };\r\n\r\n    std::cout << "\u5b89\u5168\u9664\u6cd5: 10.0 / 3.0 = " << safe_divide(10.0, 3.0) << "\\n";\r\n    std::cout << "\u5b89\u5168\u9664\u6cd5: 1.0 / 0.0 = " << safe_divide(1.0, 0.0) << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// \u65b9\u5f0f\u4e8c\uff1a\u5728\u6a21\u677f\u53c2\u6570\u5217\u8868\u4e2d\u4f7f\u7528 concept\r\ntemplate<std::integral T>\r\nT factorial(T n) {\r\n    if (n <= 1) return 1;\r\n    return n * factorial(n - 1);\r\n}\r\n\r\n// \u65b9\u5f0f\u4e09\uff1a\u5728\u8fd4\u56de\u7c7b\u578b\u524d\u4f7f\u7528 requires\r\ntemplate<typename T>\r\nrequires std::integral<T>\r\nT gcd(T a, T b) {\r\n    while (b != 0) {\r\n        T temp = b;\r\n        b = a % b;\r\n        a = temp;\r\n    }\r\n    return a;\r\n}\r\n\r\n// \u65b9\u5f0f\u56db\uff1a\u4f7f\u7528 auto \u7b80\u5199 (abbreviated template)\r\n// \u7b49\u4ef7\u4e8e template<std::integral T> void print_integral(T value)\r\nvoid print_integral(std::integral auto value) {\r\n    std::cout << "\u6574\u6570\u503c: " << value << "\\n";\r\n}\r\n\r\n// ----- \u4e0e SFINAE \u5bf9\u6bd4 -----\r\n\r\n// C++17 SFINAE \u65b9\u5f0f\uff08\u7e41\u7410\u4e14\u9519\u8bef\u4fe1\u606f\u4e0d\u53cb\u597d\uff09\r\ntemplate<typename T,\r\n         typename = std::enable_if_t<std::is_arithmetic_v<T>>>\r\nT old_style_abs(T value) {\r\n    return value < 0 ? -value : value;\r\n}\r\n\r\n// C++20 Concepts \u65b9\u5f0f\uff08\u7b80\u6d01\u4e14\u9519\u8bef\u4fe1\u606f\u53cb\u597d\uff09\r\ntemplate<typename T>\r\nrequires std::is_arithmetic_v<T>\r\nT new_style_abs(T value) {\r\n    return value < 0 ? -value : value;\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u5404\u79cd\u7ea6\u675f\u4f4d\u7f6e\u7684\u6f14\u793a\r\n    std::cout << "\u9636\u4e58 5! = " << factorial(5) << "\\n";\r\n    std::cout << "\u6700\u5927\u516c\u7ea6\u6570 gcd(12, 8) = " << gcd(12, 8) << "\\n";\r\n    print_integral(42);\r\n    print_integral(static_cast<short>(7));\r\n\r\n    // SFINAE vs Concepts \u5bf9\u6bd4\r\n    std::cout << "\\nSFINAE\u65b9\u5f0f abs(-3.14) = " << old_style_abs(-3.14) << "\\n";\r\n    std::cout << "Concepts\u65b9\u5f0f abs(-42) = " << new_style_abs(-42) << "\\n";\r\n\r\n    // \u591a\u4e2a concept \u7ea6\u675f\r\n    auto convert = []<typename From, typename To>(From value)\r\n        requires std::integral<From> && std::floating_point<To>\r\n    {\r\n        return static_cast<To>(value);\r\n    };\r\n\r\n    double result = convert.template operator()<int, double>(42);\r\n    std::cout << "\u6574\u6570\u8f6c\u6d6e\u70b9: " << result << "\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1aconcept \u7ea6\u675f\u4e0d\u662f\u8fd0\u884c\u65f6\u68c0\u67e5\uff0c\u662f\u7f16\u8bd1\u671f\u68c0\u67e5\r\n    std::cout << "1. concept \u662f\u7f16\u8bd1\u671f\u68c0\u67e5\uff0c\u4e0d\u662f\u8fd0\u884c\u65f6\u68c0\u67e5\\n";\r\n    std::cout << "   \u4ee5\u4e0b\u4ee3\u7801\u4f1a\u7f16\u8bd1\u5931\u8d25\uff08\u4e0d\u4f1a\u5230\u8fd0\u884c\u65f6\uff09\uff1a\\n";\r\n    std::cout << "   // std::integral auto x = 3.14;  // \u7f16\u8bd1\u9519\u8bef!\\n\\n";\r\n\r\n    // \u9677\u96312\uff1arequires \u5b50\u53e5\u4e2d\u7684\u8868\u8fbe\u5f0f\u5fc5\u987b\u662f\u5e03\u5c14\u7c7b\u578b\u5e38\u91cf\u8868\u8fbe\u5f0f\r\n    std::cout << "2. requires \u5b50\u53e5\u4e2d\u7684\u8868\u8fbe\u5f0f\u5fc5\u987b\u662f\u7f16\u8bd1\u671f\u5e38\u91cf\u8868\u8fbe\u5f0f\\n";\r\n    std::cout << "   \u4e0d\u80fd\u4f7f\u7528\u8fd0\u884c\u65f6\u53d8\u91cf\u4f5c\u4e3a\u7ea6\u675f\u6761\u4ef6\\n\\n";\r\n\r\n    // \u9677\u96313\uff1a\u7ea6\u675f\u4e0e\u91cd\u8f7d\u7684\u4ea4\u4e92\r\n    std::cout << "3. \u5f53\u6709\u591a\u4e2a\u91cd\u8f7d\u6ee1\u8db3\u65f6\uff0c\u7f16\u8bd1\u5668\u9009\u62e9\u7ea6\u675f\u66f4\u4e25\u683c\uff08\u66f4\u7279\u5316\uff09\u7684\u7248\u672c\\n";\r\n    std::cout << "   \u8fd9\u53eb\u505a subsumption\uff08\u5305\u542b\u5173\u7cfb\uff09\\n\\n";\r\n\r\n    // \u6f14\u793a\uff1a\u4e0d\u540c\u7ea6\u675f\u7ea7\u522b\u7684\u91cd\u8f7d\u9009\u62e9\r\n    auto describe = [](std::integral auto val) {\r\n        std::cout << "   \u6574\u6570\u7248\u672c: " << val << "\\n";\r\n    };\r\n\r\n    // \u6ce8\u610f\uff1a\u5982\u679c\u6709\u4e00\u4e2a\u66f4\u5bbd\u6cdb\u7684\u91cd\u8f7d\uff08\u5982\u63a5\u53d7 auto\uff09\uff0c\r\n    // \u7f16\u8bd1\u5668\u4f1a\u4f18\u5148\u9009\u62e9\u7ea6\u675f\u66f4\u4e25\u683c\u7684\u7248\u672c\r\n    describe(42);\r\n    describe(static_cast<char>(\'A\'));\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== Concepts \u57fa\u7840 - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(r.ul,{children:["\n",(0,s.jsx)(r.li,{children:(0,s.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/constraints",children:"cppreference: Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)"})}),"\n"]})]})}function l(n={}){const{wrapper:r}={...(0,c.R)(),...n.components};return r?(0,s.jsx)(r,{...n,children:(0,s.jsx)(d,{...n})}):d(n)}},28453(n,r,e){e.d(r,{R:()=>a,x:()=>o});var t=e(96540);const s={},c=t.createContext(s);function a(n){const r=t.useContext(c);return t.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function o(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:a(n.components),t.createElement(c.Provider,{value:r},n.children)}}}]);